 }

+
 Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (Value *V = simplifyAddInst(I.getOperand(0), I.getOperand(1),
                                  I.hasNoSignedWrap(), I.hasNoUnsignedWrap(),
@@ -1553,6 +1554,67 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (Instruction *R = combineAddSubWithShlAddSub(Builder, I))
     return R;

+  // Fold ceiling division pattern:
+  // (x >> C) + zext((x & ((1 << C) - 1)) != 0) -> (x + ((1 << C) - 1)) >> C
+  // Also handle strength-reduced form:
+  // ((x >> C) & Mask1) + zext((x & Mask2) != 0) -> ((x & FullMask) + Mask2) >> C
+  {
+    Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
+    Value *X;
+    const APInt *MaskC;
+
+    auto matchAndFold = [&](Value *LShrOp, Value *ZExtOp) -> Instruction * {
+      // Match ZExtOp: zext(icmp ne(and(X, MaskC), 0))
+      if (!match(ZExtOp, m_OneUse(m_ZExt(m_OneUse(m_SpecificICmp(
+              ICmpInst::ICMP_NE, m_OneUse(m_And(m_Value(X), m_APInt(MaskC))), m_Zero()))))))
+        return nullptr;
+
+      // MaskC must be of the form (1 << C) - 1 (all ones)
+      if (!MaskC->isMask())
+        return nullptr;
+      unsigned C = MaskC->countr_one();
+
+      // Try to match LShrOp as (x >> C) or ((x >> C) & Mask1)
+      const APInt *ShAmt;
+      
+      // Pattern 1: (x >> C)
+      if (match(LShrOp, m_OneUse(m_LShr(m_Specific(X), m_APInt(ShAmt)))) &&
+          ShAmt->getZExtValue() == C) {
+        // Check for overflow safety
+        KnownBits XKnown = computeKnownBits(X, 0, &I);
+        if (XKnown.countMinLeadingZeros() >= C) {
+          Constant *MaskConst = ConstantInt::get(X->getType(), *MaskC);
+          Value *Add = Builder.CreateAdd(X, MaskConst, "", true, false);
+          return BinaryOperator::CreateLShr(Add, ConstantInt::get(X->getType(), C));
+        }
+      }
+
+      // Pattern 2: ((x >> C) & Mask1) - strength-reduced form
+      const APInt *Mask1;
+      Value *ShlOp;
+      if (match(LShrOp, m_OneUse(m_And(m_Value(ShlOp), m_APInt(Mask1)))) &&
+          match(ShlOp, m_OneUse(m_LShr(m_Specific(X), m_APInt(ShAmt)))) &&
+          ShAmt->getZExtValue() == C) {
+        // Compute FullMask = Mask1 << C | MaskC
+        APInt FullMask = (*Mask1 << C) | *MaskC;
+        if (FullMask.isMask()) {
+          // Create: lshr(add(and(X, FullMask), MaskC), C)
+          Value *MaskedX = Builder.CreateAnd(X, ConstantInt::get(X->getType(), FullMask));
+          Constant *MaskConst = ConstantInt::get(X->getType(), *MaskC);
+          Value *Add = Builder.CreateAdd(MaskedX, MaskConst, "", true, false);
+          return BinaryOperator::CreateLShr(Add, ConstantInt::get(X->getType(), C));
+        }
+      }
+
+      return nullptr;
+    };
+
+    if (Instruction *R = matchAndFold(Op0, Op1))
+      return R;
+    if (Instruction *R = matchAndFold(Op1, Op0))
+      return R;
+  }
+
   Value *LHS = I.getOperand(0), *RHS = I.getOperand(1);
   if (Instruction *R = foldAddLikeCommutative(LHS, RHS, I.hasNoSignedWrap(),
                                               I.hasNoUnsignedWrap()))
@@ -1893,6 +1955,7 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   return Changed ? &I : nullptr;
 }

